-- Show summary
SELECT 'Test data seeded successfully!' as message;
SELECT COUNT(*) as plant_count FROM plants WHERE name IN ('Tomato Plant', 'Basil Plant', 'Lettuce Plant');
SELECT COUNT(*) as sensor_count FROM sensors WHERE name LIKE '%Tomato%' OR name LIKE '%Basil%' OR name LIKE '%Lettuce%';
SELECT COUNT(*) as reading_count FROM readings WHERE sensor_id IN (@tomato_moisture_id, @tomato_temp_id, @basil_moisture_id, @basil_humidity_id, @lettuce_moisture_id);

